const Q_CHEMISTRY_2018_MODEL_I=[{"id": "objective>Chemistry>2018-Model-I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction of Chlorine with hot concentrated Sodium hydroxide solution is represented by the equation:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2NaOH → NaClO + NaCl + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 4NaOH → 4 NaCl + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 6 NaOH → NaClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + 5NaCl + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2NaOH →  2NaCl + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">With hot concentrated alkali, a halogen (e.g Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) forms three product a trioxochalate (V) salt, halide salt and water therefore you have <br/> 3Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 6NaOH → NaClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + 5NaCl + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2018-Model-I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine is prepared on a large scale by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrolysis of concentrated sodium chloride solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">action of manganese (IV) oxide on hot concentrated hydrochloric acid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">action of concentrated tetraoxosulphate (VI) acid on sodium chloride </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidation of concentrated hydrochloric acid with potassium tetraoxomanganate (VII) </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine is prepared on a large scale by the electrolysis of concentrated sodium chloride solution. This process is known as the chlor-alkali process, where the electrolysis of sodium chloride solution produces chlorine gas at the positive electrode (anode) and hydrogen gas at the negative electrode (cathode).</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2018-Model-I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The products of the electrolysis of dilute sodium chloride using carbon electrodes are <br/>  <br/> Anode &nbsp&nbsp Cathode </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorine and sodium.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen and hydrogen.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine and hydrogen.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen and oxygen.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During electrolysis, positive ions migrate towards the cathode and negative ions towards the anode. Sodium chloride dissociates into sodium ions and chloride ions. Chloride ions being negative, migrate towards the anode and are discharged as chlorine gas. Hydrogen ions from the water migrate towards the cathode and are discharged as hydrogen gas. Sodium ions and hydroxide ions remain in the solution.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2018-Model-I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When aqueous ammonia is added to one of the following solutions, a white precipitate which dissolved in excess ammonia is formed. Identify the solution?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ZnCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">FeSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When aqueous ammonia is added to ZnCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span>, it dissolves. This is because ammonia acts as a complexing agent and forms a soluble complex with Zinc ions.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2018-Model-I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon is deposited in the exhaust pipes of cars because of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contamination of petrol with diesel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of carbon in petrol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of additives in petrol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incomplete combustion of petrol</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon is deposited in the exhaust pipes of cars primarily because of incomplete combustion of petrol. When the fuel (petrol) is burned in the engine's combustion chamber, ideally, it should be fully oxidized, resulting in the production of carbon dioxide (CO2) and water vapor. However, in real-world conditions, the combustion process may not be perfect, and some of the carbon in the petrol may not fully burn. As a result, carbon particles are formed and get carried through the exhaust system.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2018-Model-I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction represented by the equation: <br/> 5Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 8H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 5Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Mn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span>, which species is reduced?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of the reaction <br/> 5Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + 8H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → 5Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + Mn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> N.B: Reduction could mean decrease in oxidation number  <br/> Oxidation could mean increase in oxidation number. <br/> From the equation given, <br/> MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> is reduced such that the oxidation number of manganese has reduced from +7 to +2 (as in Mn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>)</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2018-Model-I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pressure of a gas varies inversely to changes in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vapour density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Concentration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Volume</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Boyle's law, at constant temperature, the pressure of a given amount of gas varies inversely with its volume. This means that if the volume of the gas increases, the pressure decreases and vice versa.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2018-Model-I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The scattering of rays of light when it is propagated along the path of a colloidal solution is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dialysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brownian motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tyndal effect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fluorescence</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The scattering of light by particles in a colloid or in a very fine suspension is known as the Tyndall effect. This effect is used to determine whether a mixture is a true solution or a colloid.</div>", "topic": "SOLUBILITY : SUSPENSIONS AND COLLOIDS"}, {"id": "objective>Chemistry>2018-Model-I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ionization energy increases across the period in the periodic table because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">atomic number increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">effective nuclear charge increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass number decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">screening effect decreases</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As the nuclear charge increases, its attraction for the outermost electron increases and so more energy is required to remove the outermost electron. Hence, the ionization energy increases.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2018-Model-I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The current carriers that are responsible for the conductance of aqueous copper (II) tetraoxosulphate (VI) solutions are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrated electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrated ions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrons </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conductance of aqueous copper (II) tetraoxosulphate (VI) solutions is due to the movement of hydrated ions. When a salt like copper (II) tetraoxosulphate (VI) dissolves in water, it dissociates into its constituent ions. These ions are surrounded by water molecules, forming hydrated ions, which are the charge carriers in the solution.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2018-Model-I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electrochemical cell is symbolically represented as Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>/Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> //Ag<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> /Ag<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> The Standard electrode potentials of the half cells , Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>/Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> and Ag<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span>)/Ag<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> are -0.76V and +0.80V respectively. What is the emf of the cell?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.56V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1.56V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+0.04v</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-0.04V</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The half cell reactions are  <br/> i. Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> → Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>, E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span> = +0.76V <br/> ii. 2Ag<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → 2Ag<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>, E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span> = +0.80V <br/> The overall cell reaction is (I) + (II) <br/> Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2Ag<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> →  Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2Ag<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">cell</span> = +1.56V</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2018-Model-I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of a catalyst in a reaction changes the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enthalpy change of reaction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equilibrium position</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yield of products </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reaction pathway</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of a catalyst in a reaction changes the reaction pathway. A catalyst works by providing an alternative reaction pathway with a lower activation energy. This allows the reaction to proceed more quickly, but it does not change the enthalpy change of the reaction, the equilibrium position, or the yield of products.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2018-Model-I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Species that occur in a reaction pathway but not in the overall reaction are known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inhibitors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reactants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intermediates</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a chemical reaction, intermediates are the chemical species that are formed during the reaction but are subsequently consumed in further steps, leading to the final products. They are transient species that exist momentarily during the reaction process and are not present in the initial reactants or the final products of the overall reaction.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2018-Model-I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Ammonium compound used in the manufacture of dry cells is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">(NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl, Ammonium chloride is used in the manufacture of Dry Leclanche cell. <br/> </div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>2018-Model-I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium constant (kp) expression involves </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gaseous species only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid, liquid and gaseous species </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Species in aqueous solution only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Species in aqueous solution and gases only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium constant (kp) expression involves gaseous species only. It is based on partial pressures.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2018-Model-I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not correct about a catalyst? It</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remains unchanged chemically at the end of a reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> helps to establish equilibrium faster reversible reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can start a chemical reaction which will normally not take place</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is usually specific in its action</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A catalyst is a substance that speeds up a chemical reaction, but is not consumed by the reaction; hence a catalyst will appear in the physical states. It does not have the ability to start a chemical reaction which will normally not take place. It only speeds up reactions that would have occurred anyway, but at a slower rate.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2018-Model-I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a physical property?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">flammability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solubility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">melting point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">viscosity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Flammability is the measurability of the propensity for a compound to combust (i.e chemically react with oxygen,) this is a chemical property.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>2018-Model-I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are Impure substances except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soft drink</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium amalgram</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mercury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brass</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mercury is a metal an element which is perfectly unmingled while Brass is a mixture of two metals Copper and Zinc, Sodium amalgam. Soft drinks are also mixtures.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : PURE AND IMPURE SUBSTANCES"}, {"id": "objective>Chemistry>2018-Model-I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following indicates that an aqueous solution is basic?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">when it contains more OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> than H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">when it contains more H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> than OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Its pH value is low </div>", "<div style=\"font-family:Cambria;font-size:17px;\">It has a sour taste</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An aqueous solution is basic if it contains more hydroxide ions (OH-) than hydronium ions (H3O+). This is because the presence of more hydroxide ions increases the pH of the solution, making it basic. The pH scale is a measure of how acidic or basic a substance is, with values below 7 indicating acidity, 7 indicating neutrality, and values above 7 indicating basicity.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2018-Model-I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following elements would displace copper from a solution of copper ions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Silver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lead</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mercury</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reactivity series allows us to predict how metals react. A more reactive metal displaces a less reactive metal from a compound. Lead is more reactive metal than copper hence, copper is displaced from copper solution by lead.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2018-Model-I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium trioxocarbonate (IV) (Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) aqueous solution is alkaline because the compound </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">undergoes hydrolysis in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionises completely in solution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is stable to heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is derived from a strong base</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium trioxocarbonate (IV) (Na2CO3) is a salt of a weak acid (carbonic acid) and a strong base (sodium hydroxide). When it dissolves in water, it undergoes hydrolysis to form a basic solution. This is because the carbonate ion reacts with water to form bicarbonate and hydroxide ions, which makes the solution alkaline.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2018-Model-I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the removal of rust from Iron, Fe what reaction is involved if its treated with H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis of rust</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dehydration of rust </div>", "<div style=\"font-family:Cambria;font-size:17px;\">acid-base reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidation of rust</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The removal of rust from iron by treatment with tetraoxosulphate (IV) acid is based on the oxidation of the rust.</div>", "topic": "ELECTROLYSIS : CORROSION"}, {"id": "objective>Chemistry>2018-Model-I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What makes ionic solids generally stable?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">london dispersion forces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystal lattice forces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vander waals foces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen bonds </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ionic solids are generally stable due to the strong electrostatic forces of attraction between the positive and negative ions in a crystal lattice. These forces, known as crystal lattice forces, hold the ions in a fixed, regular arrangement, giving ionic solids their characteristic properties such as high melting and boiling points.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2018-Model-I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The higher or larger the electronegativity difference between two elements, the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lower the polarity of their inter atomic bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">higher the polarity of their inter atomic bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">weaker their interatomic bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">higher the possibility of forming a molecule </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electronegativity is a measure of the ability of an atom to attract electrons. When two elements have a large difference in electronegativity, the more electronegative atom will attract the electrons more strongly, creating a polar bond. Therefore, the larger the electronegativity difference between two elements, the higher the polarity of their interatomic bond.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2018-Model-I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Diamond is a hard substance because its carbon atoms are held by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">delocalised electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">strong electrostatic forces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">van der waals forces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">strong directional covalent bonds </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diamond is a hard substance because its carbon atoms are held by strong directional covalent bonds. In a diamond, each carbon atom is covalently bonded to four other carbon atoms in a tetrahedral structure, which makes it extremely hard.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2018-Model-I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the electronegativity difference between X and Y is zero, the interatomic bond between them is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ionic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-polar covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polar covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coordinate covalent</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A non-polar covalent bond is formed if the electronegativity difference between two combining atom is small.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2018-Model-I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Green house effect can be reduced by controlling </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">burning of wood and fossil fuel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of aerosols </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of artificial fertilizers </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fossil fuels contain Carbon which are emitted when burnt. </div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2018-Model-I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A solution of a salt X reacts with AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> solution to give white precipitate which dissolves in excess aqueous ammonia X contains </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A solution of a salt X reacts with AgNO3 solution to give white precipitate which dissolves in excess aqueous ammonia. This is a characteristic reaction of chloride ions (Cl-). When AgNO3 is added to a solution containing chloride ions, a white precipitate of AgCl is formed. This precipitate dissolves in excess aqueous ammonia.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2018-Model-I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these salts crystalizes with water of crystallization?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaCl</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CuSO4 is a salt that crystallizes with water of crystallization. Water of crystallization is the fixed number of water molecules chemically attached to each formula unit of a salt in its crystalline form. In the case of CuSO4, it forms blue crystals of CuSO4.5H2O, where 5 molecules of water are attached to each formula unit of CuSO4.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2018-Model-I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an exothermic reaction the position of equilibrium can be shifted forward by ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increasing pressure at constant temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing pressure at constant temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing temperature at constant pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing temperature at constant pressure</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an exothermic reaction, heat is released. According to Le Chatelier's principle, the system will shift in the direction that opposes the change. Therefore, decreasing the temperature will shift the equilibrium to the right, favoring the forward reaction to produce more heat.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2018-Model-I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ; ΔH = -365KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> ΔH in the equation above represents </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heat of atomization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionization energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dissociation energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electron affinity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electron affinity is the energy released when one mole of electrons are added to one mole of gaseous atoms to form one mole of the corresponding anions in the gas phase.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2018-Model-I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the relative molecular mass of Calcium hydrogen tetraoxosulphate (VI) <br/> [Ca = 40, H = 1, S = 32, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">106</div>", "<div style=\"font-family:Cambria;font-size:17px;\">136</div>", "<div style=\"font-family:Cambria;font-size:17px;\">233</div>", "<div style=\"font-family:Cambria;font-size:17px;\">234</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calcium Hydrogen tetraoxosulphate (VI) = Ca(HSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  = 40 + 2(1 + 32 + 4(16)) <br/>  = 40 + 2(33 + 64) <br/>  = 40 + 2(97) <br/>  = 40 + 194  <br/>  = 234</div>", "topic": "CHEMICAL COMBINATION : RELATIVE ATOMIC MASS BASED ON CARBON 12"}, {"id": "objective>Chemistry>2018-Model-I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The atomic number of elements X and Y are 20 and 17 respectively, which of the following compounds is likely to be formed by the combination of two elements?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">XY</div>", "<div style=\"font-family:Cambria;font-size:17px;\">XY<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">XY<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Y</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">20</span>X → A group 2 element : X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> <br/> <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">17</span>Y → A group 7 element: Y<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> <br/> X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> and Y<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> will bond electronvalently to have: XY<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2018-Model-I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What mass of Sulphur (IV) oxide is produced when 24.0g or Sulphur react with 16g of oxygen? <br/> (S = 32, O = 16)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32.0g</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a chemical reaction to have a quantilative meaning it must be balanced <br/> S + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2 (g)</span> → SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> Molar mass of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 32 + 2(16) = 64 <br/> Since mass of sulphur = 24g <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">No</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">moles</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">sulphur</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">23<hr size=\"1\" />32</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />4</td></tr></table></div> <br/>   = 0.75 mol <br/> And mass of oxygen = 16g <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">no</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">moles</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">16<hr size=\"1\" />32</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5</td><td style=\"text-align:center;\">mole</td></tr></table></div> <br/> From the balanced chemical equation (mole of sulphur reacted with 1 mole of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) <br/> Therefore 0.75 mole of sulphur reacted with 0.75mol of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Henc, sulphur is in excess and oxygen is the limiting reagent <br/> So it determines the product formed therefore, <br/> 1 mole of oxygen produced 1 mole of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Hence, 0.75 mol of oxygen will produce 0.75 mole of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">No.</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">moles</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />molar mass</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.5mol</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />64</td></tr></table></div> <br/> Mass of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> produced = 0.5 × 64 = 32g</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2018-Model-I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following methods are suitable for preparing acids except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">action of water on acid anhydrides </div>", "<div style=\"font-family:Cambria;font-size:17px;\">precipitation of insoluble sulphides from metallic salts by hydrogen sulphide gas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">action of alkalis on acidic oxides </div>", "<div style=\"font-family:Cambria;font-size:17px;\">displacement from metallic salt by less volatile acids </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Action of alkalis on acidic oxides cannot produce acid but salts e.g SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2NaOH → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2018-Model-I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 50 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a saturated solution of KNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> at 40 °C contained 5:05 g of the salt, its solubility at the same temperature would be <br/> [KNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 101]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V= 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Mass= 5.05g <br/> Relative molecular mass of KNO3 = (39+14+(3*16)) = 101 <br/> Convert 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> to dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> which is <br/> 1000cm³ = 1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> 50cm³ = 50*1/1000 <br/> = 0.05dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Moles = mass/ molar mass <br/> = 5.05/101 =0.05mole <br/> Solubility= mole/volume <br/> Solubility=0.05mol/0.05dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Solubility=1.0mol/dm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2018-Model-I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What number of moles of oxygen would exert a pressure of 10 atm at 320 K in an 8.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> cylinder? <br/> [R=0.082 atm dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.32</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.52</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.13</div>", "<div style=\"font-family:Cambria;font-size:17px;\">31.25</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P = 10atm,  T= 320K,   V= 8.2dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> PV =nRT <br/> n = P * V/R * T <br/> 10 * 8.2/0.082 * 320 <br/> = 82/26.24 <br/> n = 3.13</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2018-Model-I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the letters represents an alkaline Earth metal?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">D</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Group 2 elements are generally known as Alkaline Earth Metals</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2018-Model-I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas occupies a volume of 250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 27°C and 0.6atm its volume at s.t.p is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">137cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">169cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">416cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Volume of gas (V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) = 250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Initial temperature (T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) = (27 + 273)K = 300K <br/> Initial pressure (P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) = 0.6 atm <br/> At s.t.p, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 1atm, temperature = 273K, v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> Recall, <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.6 × 250<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1 × V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />273</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">273x0.6x250<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">136.5</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 136.5cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>2018-Model-I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many atoms are there in one mole of hydrogen gas? <br/> [Avogadro's constant = 6.02 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One mole of hydrogen gas (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) contains 2 atoms of hydrogen.  <br/>  <br/> Therefore, using Avogadro's constant (6.02 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>), <br/> 1 mole of hydrogen contains the number of atoms of hydrogen × Avogadro's constant = 2 × 6.02 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> = 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span> atoms</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}];
